const fs = require('fs');

function patch(filePath, replacements) {
  let content = fs.readFileSync(filePath, 'utf8');
  // Normalize to LF for matching
  const normalized = content.replace(/\r\n/g, '\n');
  let modified = normalized;
  for (const [from, to] of replacements) {
    if (modified.includes(from)) {
      modified = modified.split(from).join(to);
      console.log(' - replaced:', from.substring(0, 50).trim() + '...');
    } else {
      console.warn(' - NOT FOUND:', from.substring(0, 60).trim());
    }
  }
  if (modified !== normalized) {
    // Write back with CRLF
    fs.writeFileSync(filePath, modified.replace(/\n/g, '\r\n'), 'utf8');
    console.log('Patched:', filePath);
  }
}

